patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..a95c0d98206c 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -9425,6 +9425,30 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
       (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_UGE) &&
       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
     return CmpPredicate::getMatching(LPred, RPred).has_value();
+  // icmp eq/ne (sub (ptrtoint P0) (ptrtoint P1)), C where C is known non-zero
+  // implies P0 != P1.
+  if ((LPred == CmpInst::ICMP_EQ || LPred == CmpInst::ICMP_NE) &&
+      R0->getType()->isPointerTy() && R1->getType()->isPointerTy()) {
+    const Value *P0, *P1, *C;
+    if (match(L0, m_Sub(m_PtrToInt(m_Value(P0)), m_PtrToInt(m_Value(P1)))) &&
+        match(L1, m_Specific(C))) {
+      // Check if C is known non-zero.
+      if (!computeConstantRange(C, /*ForSigned=*/false, /*UseInstrInfo=*/true,
+                                /*AC=*/nullptr, /*CtxI=*/nullptr,
+                                /*DT=*/nullptr, /*Depth=*/0)
+               .contains(APInt::getZero(C->getType()->getScalarSizeInBits()))) {
+        // LHS being true means P0 != P1.
+        // If RHS is ICMP_EQ, return false (P0 != P1 means icmp eq is false).
+        // If RHS is ICMP_NE, return true (P0 != P1 means icmp ne is true).
+        if (RPred == CmpInst::ICMP_EQ)
+          return !LHSIsTrue;
+        if (RPred == CmpInst::ICMP_NE)
+          return LHSIsTrue;
+      }
+    }
+  }
+
+

   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);

